+async function waitForState<T>(reader: () => Promise<T>, timeoutMs: number = 750): Promise<T> {
+  const deadline = Date.now() + timeoutMs;
+  let last: T;
+  while (true) {
+    last = await reader();
+    if (last) return last;
+    if (Date.now() >= deadline) return last;
+    await new Promise((resolve) => setTimeout(resolve, 25));
+  }
+}
